// MARK: - URL Query Parameters

class URLQueryParameters {
    var queryParams: [String: String] = [:]
    
    init?(queryString: String?) {
        guard let queryString = queryString,
              let paramsArray = queryItems(for: queryString)
        else { return nil }
        
        for param in paramsArray {
            queryParams[param.key] = param.value
        }
    }
    
    private func queryItems(for string: String) -> [(key: String, value: String)]? {
        guard let urlComps = URLComponents(string: string) else { return nil }
        
        var comps = urlComps.queryItems ?? []
        
        for item in comps {
            if let key = item.name,
               let value = item.value
            {
                return [(key, value)]
            } else if let items = (item as? [URLQueryItem])?.compactMap({ $0 }) {
                var temp: [(key: String, value: String)] = []
                
                for item in items {
                    temp.append((item.name ?? "", item.value ?? ""))
                    
                    return temp
                }
            } else if let dict = (item as? [URLQueryItem: String]) {
                var temp: [(key: String, value: String)] = []
                
                for (k, v) in dict {
                    temp.append((k, v))
                    
                    return temp
                }
            }
        }
        
        return nil
    }
}

